    kib = kbi/33.5e-3f;
    kpp1 = 1.72f;
    Kmpp1 = 11.5f;
    kib2 = kib;
    kb2i = kib2*5.0f;
    kb24 = k24;
    kb42 = k42*33.5e-3f/5.0f;
    kta = kbi/1000.0f;
    kat = kib;
    kt42 = k42*33.5e-6f/5.0f;
    kt24 = k24;
    kat2 = kib;
    kt2a = kib*5.0f;

    kcanCaoff = 1.0f;
    kcanCaon = kcanCaoff/0.5f;
    kcanCaM4on = 46.0f;
    kcanCaM4off = 0.0013f;
    kcanCaM2on = kcanCaM4on;
    kcanCaM2off = 2508.0f*kcanCaM4off;
    kcanCaM0on = kcanCaM4on;
    kcanCaM0off = 165.0f*kcanCaM2off;
    k02can = k02;
    k20can = k20/165.0f;
    k24can = k24;
    k42can = k20/2508.0f;

    rcn02 = k02*pow_fp(Ca,2.0f)*CaM - k20*Ca2CaM;
    rcn24 = k24*pow_fp(Ca,2.0f)*Ca2CaM - k42*Ca4CaM;

    B = Btot - CaMB - Ca2CaMB - Ca4CaMB;
    rcn02B = k02B*pow_fp(Ca,2.0f)*CaMB - k20B*Ca2CaMB;
    rcn24B = k24B*pow_fp(Ca,2.0f)*Ca2CaMB - k42B*Ca4CaMB;
    rcn0B = k0Bon*CaM*B - k0Boff*CaMB;
    rcn2B = k2Bon*Ca2CaM*B - k2Boff*Ca2CaMB;
    rcn4B = k4Bon*Ca4CaM*B - k4Boff*Ca4CaMB;

    Ca2CaN = CaNtot - Ca4CaN - CaMCa4CaN - Ca2CaMCa4CaN - Ca4CaMCa4CaN;
    rcnCa4CaN = kcanCaon*pow_fp(Ca,2.0f)*Ca2CaN - kcanCaoff*Ca4CaN;
    rcn02CaN = k02can*pow_fp(Ca,2.0f)*CaMCa4CaN - k20can*Ca2CaMCa4CaN;
    rcn24CaN = k24can*pow_fp(Ca,2.0f)*Ca2CaMCa4CaN - k42can*Ca4CaMCa4CaN;
    rcn0CaN = kcanCaM0on*CaM*Ca4CaN - kcanCaM0off*CaMCa4CaN;
    rcn2CaN = kcanCaM2on*Ca2CaM*Ca4CaN - kcanCaM2off*Ca2CaMCa4CaN;
    rcn4CaN = kcanCaM4on*Ca4CaM*Ca4CaN - kcanCaM4off*Ca4CaMCa4CaN;

    Pix = 1.0f - Pb2 - Pb - Pt - Pt2 - Pa;
    rcnCKib2 = kib2*Ca2CaM*Pix - kb2i*Pb2;
    rcnCKb2b = kb24*pow_fp(Ca,2.0f)*Pb2 - kb42*Pb;
    rcnCKib = kib*Ca4CaM*Pix - kbi*Pb;
    T = Pb + Pt + Pt2 + Pa;
    kbt = 0.055f*T + 0.0074f*pow_fp(T,2.0f) + 0.015f*pow_fp(T,3.0f);
