__kernel void kernel_master(
    int timeinst,
    __global fp* initvalu,
    __global fp* finavalu,
    __global fp* parameter,
    __global fp* com)
{
    int gid = get_global_id(0);

    int initvalu_offset_ecc = 0;
    int parameter_offset_ecc = 0;
    int initvalu_offset_Dyad = 46;
    int parameter_offset_Dyad = 1;
    int initvalu_offset_SL = 61;
    int parameter_offset_SL = 6;
    int initvalu_offset_Cyt = 76;
    int parameter_offset_Cyt = 11;

    if (gid == 0) {
        // ecc function is not implemented here due to complexity and size.
        // This kernel only implements cam calls and stores results in com.
        // The ecc function should be run on host or separate kernel.
    }
    else if (gid == 1) {
        fp CaDyad = initvalu[initvalu_offset_Dyad+35]*1e3f;
        fp JCaDyad = cam((fp)timeinst, initvalu, initvalu_offset_Dyad, parameter, parameter_offset_Dyad, finavalu, CaDyad);
        com[0] = JCaDyad;
    }
    else if (gid == 2) {
        fp CaSL = initvalu[initvalu_offset_SL+36]*1e3f;
        fp JCaSL = cam((fp)timeinst, initvalu, initvalu_offset_SL, parameter, parameter_offset_SL, finavalu, CaSL);
        com[1] = JCaSL;
    }
    else if (gid == 3) {
        fp CaCyt = initvalu[initvalu_offset_Cyt+37]*1e3f;
        fp JCaCyt = cam((fp)timeinst, initvalu, initvalu_offset_Cyt, parameter, parameter_offset_Cyt, finavalu, CaCyt);
        com[2] = JCaCyt;
    }
}
